import{c as e,Q as a,j as r,m as o}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"Usage","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/finance/usage.md","filePath":"guide/admin/finance/usage.md","lastUpdated":1778862269000}'),n={name:"guide/admin/finance/usage.md"};function s(d,t,i,l,u,g){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h1><p>The <strong>Finance → Usage</strong> page is the query interface for usage aggregates. Use it to answer questions like &quot;how much did Acme&#39;s PROD tenant consume last month?&quot; without issuing an invoice.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>Header, token-based search field with a collapsible date-range row, results table.</p><h2 id="token-filters" tabindex="-1">Token filters <a class="header-anchor" href="#token-filters" aria-label="Permalink to &quot;Token filters&quot;">​</a></h2><p>The search field is token-aware. Use the syntax <code>field:value</code> to add filters. The field labels and option names are both searchable — typing <code>customer:Acme</code> and typing <code>customer:abc123</code> (an ID) both work.</p><table tabindex="0"><thead><tr><th>Token</th><th>Cardinality</th><th>Notes</th></tr></thead><tbody><tr><td><code>customer:&lt;name&gt;</code></td><td>single</td><td>One customer scope.</td></tr><tr><td><code>tenant:&lt;name&gt;</code></td><td>single</td><td>One tenant scope.</td></tr><tr><td><code>env:&lt;value&gt;</code></td><td>multi</td><td>DEV / QA / UAT / STAGING / DEMO / PREPROD / PROD.</td></tr><tr><td><code>meter:&lt;name&gt;</code></td><td>multi</td><td>Built-in and custom meters.</td></tr><tr><td><code>granularity:&lt;value&gt;</code></td><td>single, <strong>required</strong></td><td>hourly / daily / monthly.</td></tr></tbody></table><p>Negation is not supported in this field.</p><p>The result count is shown on the right.</p><h2 id="date-range" tabindex="-1">Date range <a class="header-anchor" href="#date-range" aria-label="Permalink to &quot;Date range&quot;">​</a></h2><p>Click <strong>Date range</strong> to expand a secondary row with <strong>From date</strong> and <strong>To date</strong> pickers. Clear by clicking <strong>Clear all</strong> in the toolbar.</p><h2 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Customer</strong></td><td>Name (falls back to ID).</td></tr><tr><td><strong>Tenant</strong></td><td>Name (falls back to ID).</td></tr><tr><td><strong>Meter</strong></td><td>Display name.</td></tr><tr><td><strong>Granularity</strong></td><td>Hourly / Daily / Monthly badge.</td></tr><tr><td><strong>Period</strong></td><td>Date range, monospace.</td></tr><tr><td><strong>Total Value</strong></td><td>Raw aggregated usage in the period, formatted.</td></tr><tr><td><strong>Billed Value</strong></td><td>What the customer is charged for after plan limits, multipliers, and overrides are applied. Monospace, bold.</td></tr><tr><td><strong>Peak</strong></td><td>Maximum value in the period (per the meter&#39;s aggregation mode).</td></tr><tr><td><strong>Computed</strong></td><td>When the aggregation was computed.</td></tr></tbody></table><h2 id="total-vs-billed-vs-peak" tabindex="-1">Total vs. Billed vs. Peak <a class="header-anchor" href="#total-vs-billed-vs-peak" aria-label="Permalink to &quot;Total vs. Billed vs. Peak&quot;">​</a></h2><ul><li><strong>Total Value</strong> is the raw aggregate of measurements in the period.</li><li><strong>Billed Value</strong> is what would actually be invoiced. It applies the plan&#39;s included quantity, the customer&#39;s non-production multiplier, any per-tenant overrides, and credits. This is usually what you want.</li><li><strong>Peak</strong> is the maximum during the period — useful for snapshot-mode meters (e.g. peak concurrent users).</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><strong>Granularity is required.</strong> The query will not run until you pick one. Hourly is for spot checks; monthly is for invoice reconciliation; daily is the typical default.</li><li>The page is a query tool. It does not modify anything — issuing an invoice happens on <a href="./customer-billing">Customer Billing</a>.</li><li>For aggregates across many customers, <a href="./customer-finance">Customer Finance</a> exports a Usage Report CSV that may be a faster path.</li></ul>',17)])])}const m=e(n,[["render",s]]);export{c as __pageData,m as default};
